def set_background(theme='Gradient', image_url=None, overlay_opacity=0.70):
        if theme == 'Default':
                css = """
                <style>
                [data-testid="stAppViewContainer"]{background:transparent}
                </style>
                """
        elif theme == 'Gradient':
                css = """
                <style>
                [data-testid="stAppViewContainer"]{
                    background: linear-gradient(135deg,#f5f7fa 0%, #c3cfe2 100%);
                }
                </style>
                """
        else:
                # Image background with optional dark overlay for readability
                overlay = f"rgba(0,0,0,{overlay_opacity})"
                img = image_url or 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=1650&q=80'
                css = f"""
                <style>
                [data-testid="stAppViewContainer"]{{
                    background-image: url('{img}');
                    background-size: cover;
                    background-repeat: no-repeat;
                    background-attachment: fixed;
                    position: relative;
                }}
                [data-testid="stAppViewContainer"]:before{{
                    content: "";
                    position: absolute;
                    inset: 0;
                    background: linear-gradient({overlay}, {overlay});
                    mix-blend-mode: multiply;
                    pointer-events: none;
                }}
                </style>
                """

        st.markdown(css, unsafe_allow_html=True)

# Theme controls in sidebar
theme_choice = st.sidebar.selectbox("Background Theme", ["Gradient", "Image", "Default"], index=0)
bg_image = None
overlay_opacity = 0.35
if theme_choice == 'Image':
        bg_image = st.sidebar.text_input("Background image URL", value="")
        overlay_opacity = st.sidebar.slider("Overlay opacity", min_value=0.0, max_value=0.9, value=0.35)

set_background(theme_choice, image_url=bg_image or None, overlay_opacity=overlay_opacity)

## Uploading csv/excel file (moved to sidebar)
uploaded_file = st.sidebar.file_uploader("Upload statement in CSV or Excel format", type=["csv", "xlsx"]) 
if not uploaded_file:
    st.info("Please upload a CSV or Excel file to continue.")
    st.stop()

if uploaded_file.name.endswith(".csv"):
    df = pd.read_csv(uploaded_file)
else:
    df = pd.read_excel(uploaded_file)

st.write("Raw Data")
st.dataframe(df)

## Ensure expected columns exist
if 'Debit' not in df.columns:
    df['Debit'] = 0
if 'Credit' not in df.columns:
    df['Credit'] = 0
if 'Description' not in df.columns:
    df['Description'] = ''

## Cleaning debit and credit columns and handling missing values
df['Debit'] = df['Debit'].replace(",", "", regex=True)
df['Credit'] = df['Credit'].replace(",", "", regex=True)
df['Debit'] = pd.to_numeric(df['Debit'], errors='coerce').fillna(0)
df['Credit'] = pd.to_numeric(df['Credit'], errors='coerce').fillna(0)

## Calculating total income and expenses
total_expense = df['Debit'].sum()
total_income = df['Credit'].sum()
st.write("### Expenses")
expenses = df[df['Debit'] > 0]
st.dataframe(expenses)

st.write("### Income")
income = df[df['Credit'] > 0]
st.dataframe(income)

## Function to categorize using keywords
def categorize(description):
    description = str(description).lower()

    if 'amazon' in description or 'flipkart' in description or 'myntra' in description:
        return 'Shopping'
    elif 'swiggy' in description or 'zomato' in description or 'blinkit' in description:
        return 'Food'
    elif 'uber' in description or 'ola' in description or 'rapido' in description or 'metro' in description or 'auto' in description or 'bus' in description:
        return 'Transport'
    elif 'salary' in description or 'interest' in description or 'dividend' in description:
        return 'Income'
    elif 'rent' in description or 'house' in description or 'apartment' in description:
        return 'Rent'
    elif 'netflix' in description or 'spotify' in description or 'prime' in description:
        return 'Entertainment'
    elif 'doctor' in description or 'hospital' in description or 'pharmacy' in description:
        return 'Health'
    elif 'school' in description or 'college' in description or 'course' in description:
        return 'Education'
    elif 'electricity' in description or 'water' in description or 'gas' in description:
        return 'Utilities'
    elif 'gym' in description or 'fitness' in description or 'yoga' in description:
        return 'Fitness'
    elif 'grocery' in description or 'supermarket' in description or 'bigbasket' in description:
        return 'Groceries'
    elif 'recharge' in description or 'mobile' in description or 'dth' in description:
        return 'Mobile Recharge'
    elif 'gift' in description or 'donation' in description or 'charity' in description:
        return 'Gifts & Donations'
    elif 'restaurant' in description or 'cafe' in description or 'dining' in description:
        return 'Dining'
    elif 'atm' in description or 'bank' in description or 'finance' in description or 'mutual' in description or 'equity' in description:
        return 'Financial Services'
    elif 'travel' in description or 'flight' in description or 'hotel' in description or 'booking' in description:
        return 'Travel'
    else:
        return 'Other'

df['Category'] = df['Description'].apply(categorize)

## Adding date filtering
if 'Date' not in df.columns:
    st.error("No 'Date' column found in uploaded file.")
else:
    # convert original Date column to datetime and create a plain date column for UI
    df['Date'] = pd.to_datetime(df['Date'], errors='coerce')
    df['date'] = df['Date'].dt.date

    start_date = st.sidebar.date_input("Start Date", df['date'].min())
    end_date = st.sidebar.date_input("End Date", df['date'].max())
    category_filter = st.sidebar.multiselect("Categories", options=sorted(df['Category'].unique()), default=[]) 

    filtered_df = df[(df['date'] >= start_date) & (df['date'] <= end_date)]
    if category_filter:
        filtered_df = filtered_df[filtered_df['Category'].isin(category_filter)]

    st.write("### Filtered Data")
    st.dataframe(filtered_df)

    # KPIs based on filtered data
    f_total_expense = filtered_df['Debit'].sum()
    f_total_income = filtered_df['Credit'].sum()
    c1, c2, c3 = st.columns(3)
    c1.metric("Total Income", f"₹{f_total_income:,.2f}")
    c2.metric("Total Expense", f"₹{f_total_expense:,.2f}")
    c3.metric("Total Savings", f"₹{(f_total_income - f_total_expense):,.2f}")

    # Category summary and interactive charts
    category_summary = filtered_df.groupby('Category')['Debit'].sum().reset_index()
    st.write("### Spending by Category")
    st.dataframe(category_summary)

    if not category_summary.empty:
        pie = px.pie(
            category_summary,
            names='Category',
            values='Debit',
            title='Spending by Category',
            hole=0.4,
            color_discrete_sequence=px.colors.qualitative.Plotly,
            template='plotly_white',
        )
        pie.update_traces(textposition='inside', textinfo='percent+label')
        pie.update_layout(margin=dict(t=40, b=0, l=0, r=0), paper_bgcolor='rgba(0,0,0,0)')
        st.plotly_chart(pie, use_container_width=True)

    # Monthly expenses time series
    if not filtered_df.empty:
        monthly = filtered_df.set_index('Date').resample('M')['Debit'].sum().reset_index()
        if not monthly.empty:
            line = px.line(
                monthly,
                x='Date',
                y='Debit',
                title='Monthly Expenses',
                template='plotly_white',
                color_discrete_sequence=[px.colors.sequential.Teal[3]],
            )
            line.update_layout(margin=dict(t=40), xaxis_title=None, yaxis_title='Expense (₹)')
            line.update_traces(mode='lines+markers')
            st.plotly_chart(line, use_container_width=True)

